'use strict';

/**
 * Sliding window rate limiting middleware for Express.
 *
 * This is a TRUE sliding window: every individual request timestamp is tracked
 * per client, and on each request all timestamps older than `windowMs` are
 * evicted before counting. There is no fixed interval that "resets" the count
 * for everyone at once — the window slides continuously with the current time.
 *
 * @param {Object}  [options]
 * @param {number}  [options.windowMs=60000]          Window size in milliseconds.
 * @param {number}  [options.maxRequests=100]         Max requests per window per client.
 * @param {number}  [options.cleanupIntervalMs=60000] How often the background sweep runs.
 * @param {Function}[options.keyGenerator]            (req) => string. Defaults to req.ip.
 * @returns {Function} Express middleware. Also exposes `.close()` to stop the
 *                     cleanup timer (so it can't keep the process alive) and
 *                     `.reset()` to clear all tracked state.
 */
function createRateLimiter(options = {}) {
  const {
    windowMs = 60000,
    maxRequests = 100,
    cleanupIntervalMs = 60000,
    keyGenerator = (req) => req.ip,
  } = options;

  if (!Number.isFinite(windowMs) || windowMs <= 0) {
    throw new TypeError('windowMs must be a positive number');
  }
  if (!Number.isInteger(maxRequests) || maxRequests <= 0) {
    throw new TypeError('maxRequests must be a positive integer');
  }

  // Map<clientKey, number[]> — each value is a chronologically-ordered array of
  // request timestamps (ms since epoch).
  const hits = new Map();

  const middleware = function rateLimiter(req, res, next) {
    const key = keyGenerator(req);
    const now = Date.now();
    const windowStart = now - windowMs;

    let timestamps = hits.get(key);
    if (timestamps === undefined) {
      timestamps = [];
      hits.set(key, timestamps);
    }

    // --- Slide the window: drop everything older than windowMs. ---
    // Timestamps are appended in chronological order, so stale entries are
    // always a prefix. Find the first still-valid index and splice the rest off.
    let firstValid = 0;
    while (firstValid < timestamps.length && timestamps[firstValid] <= windowStart) {
      firstValid++;
    }
    if (firstValid > 0) {
      timestamps.splice(0, firstValid);
    }

    const count = timestamps.length;

    if (count >= maxRequests) {
      // --- Rejected: at or over the limit. ---
      // A slot frees when the OLDEST in-window request expires.
      const oldest = timestamps[0];
      const resetMs = oldest + windowMs;
      const retryAfterSec = Math.max(1, Math.ceil((resetMs - now) / 1000));

      res.setHeader('X-RateLimit-Limit', maxRequests);
      res.setHeader('X-RateLimit-Remaining', 0);
      res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));
      res.setHeader('Retry-After', retryAfterSec);

      res.status(429).json({
        error: 'Rate limit exceeded',
        retryAfter: retryAfterSec,
      });
      return; // Do NOT call next().
    }

    // --- Allowed: record this request and pass through. ---
    timestamps.push(now);

    const remaining = maxRequests - timestamps.length;
    const oldest = timestamps[0];            // soonest a slot frees up
    const resetMs = oldest + windowMs;

    res.setHeader('X-RateLimit-Limit', maxRequests);
    res.setHeader('X-RateLimit-Remaining', Math.max(0, remaining));
    res.setHeader('X-RateLimit-Reset', Math.ceil(resetMs / 1000));

    next();
  };

  // --- Periodic cleanup: evict clients with no activity inside the window. ---
  // Without this, the Map grows unbounded as new IPs appear (memory leak).
  const cleanupTimer = setInterval(() => {
    const cutoff = Date.now() - windowMs;
    for (const [key, timestamps] of hits) {
      // Last element is the most recent request for this client.
      if (timestamps.length === 0 || timestamps[timestamps.length - 1] <= cutoff) {
        hits.delete(key);
      }
    }
  }, cleanupIntervalMs);

  // unref() so this timer never keeps the Node process alive on its own.
  if (typeof cleanupTimer.unref === 'function') {
    cleanupTimer.unref();
  }

  // Stop the timer explicitly (e.g. on shutdown or in tests).
  middleware.close = function close() {
    clearInterval(cleanupTimer);
    hits.clear();
  };

  middleware.reset = function reset() {
    hits.clear();
  };

  return middleware;
}

module.exports = createRateLimiter;
module.exports.createRateLimiter = createRateLimiter;
