 * 
 * TRUE sliding window implementation (not fixed window / bucket with resets).
 * 
 * Each client IP maintains a list of request timestamps. On every request:
 * - All timestamps older than (now - windowMs) are discarded.
 * - If the number of remaining timestamps >= maxRequests, the request is rejected.
 * - Otherwise the current timestamp is appended and the request proceeds.
 * 
 * This produces a genuinely sliding enforcement: the "window" moves continuously
 * with wall time rather than resetting on a fixed schedule.
 * 
 * Memory:
 * - A periodic cleanup (every 60s) prunes IP entries that have no timestamps
 *   within the last `windowMs`.
 * - Call the returned middleware's `.close()` method (or the creator's cleanup handle)
 *   during graceful shutdown to clear the interval timer and allow the process to exit.
 * 
 * IMPORTANT NOTE ON req.ip / PROXIES:
 * Express `req.ip` is derived from the socket's remote address unless you tell
 * Express to trust proxy headers. If your app sits behind a reverse proxy
 * (Nginx, Cloudflare, load balancer, etc.), you MUST configure:
 * 
 *     app.set('trust proxy', 1);           // trust first hop
 *     // or app.set('trust proxy', 'loopback', 'linklocal', 'uniquelocal');
 * 
 * Without this setting, `req.ip` will be the proxy's IP for every client and
 * rate limiting will effectively apply a single global bucket. See:
 * https://expressjs.com/en/guide/behind-proxies.html
 */

function createRateLimiter(options = {}) {
  const windowMs = Number.isFinite(options.windowMs) && options.windowMs > 0
    ? options.windowMs
    : 60000;

  const maxRequests = Number.isFinite(options.maxRequests) && options.maxRequests > 0
    ? Math.floor(options.maxRequests)
    : 100;

  // ip -> number[] (sorted ascending timestamps in ms)
  const requestTimestamps = new Map();

  // Periodic cleanup: every 60 seconds, drop IPs that have no recent activity.
  // Using a fixed 60s interval per requirements (independent of windowMs).
  const CLEANUP_INTERVAL_MS = 60000;
  let cleanupTimer = null;

  function runCleanup() {
    const now = Date.now();
    const cutoff = now - windowMs;

    for (const [ip, timestamps] of requestTimestamps) {
      // Keep only timestamps still inside the window
      const recent = timestamps.filter((t) => t > cutoff);
      if (recent.length === 0) {
        requestTimestamps.delete(ip);
      } else if (recent.length !== timestamps.length) {
        // Only write back if we actually removed something (saves a tiny bit of churn)
        requestTimestamps.set(ip, recent);
      }
    }
  }

  function startCleanup() {
    if (cleanupTimer) return;
    cleanupTimer = setInterval(runCleanup, CLEANUP_INTERVAL_MS);
    // Allow process to exit if this is the only remaining timer
    if (typeof cleanupTimer.unref === 'function') {
      cleanupTimer.unref();
    }
