  }

  // Expose controls on the middleware function itself (convenient for app.use)
  rateLimitMiddleware.close = stopCleanup;
  rateLimitMiddleware.startCleanup = startCleanup; // in case someone stopped it
  rateLimitMiddleware.runCleanup = runCleanup;     // exposed primarily for testing / diagnostics

  // Also expose internals for testing / advanced use (non-enumerable)
  Object.defineProperty(rateLimitMiddleware, '_store', {
    value: requestTimestamps,
    enumerable: false,
    writable: false
  });
  Object.defineProperty(rateLimitMiddleware, '_cleanupTimer', {
    get: () => cleanupTimer,
    enumerable: false
  });

  return rateLimitMiddleware;
}

